%%%%%%%%%% Function fGetDirNamV01.m %%%%%%%%%%% Get only a name of directory from full path, ver.1%% Kei Nakamura% Created on Tuesday, May 15th 2007.% Modified on%% function dNam = fGetDirNamV01(fPath);% gives only a name of directory from full path.% fPath: full path% dNam: directory namefunction dNam = fGetDirNamV01(fPath);   % function headerfPathD = double(fPath);k = find(fPathD == 47);         % find '/'dNam = fPath(max(k)+1:end);
